 INSERT INTO mindshare.mindshare_post_test (post_id, project_keyword, user_x_id, full_text, retweeted_post_id, replied_post_id, quoted_post_id, root_post_id, view_count, reply_count, retweet_count, quote_count, favorite_count, post_created_at, created_at, updated_at, sentiment_score, sentiment_label, entities, content_score, latest_reply_at) VALUES ('2069372603408826424', 'Acurast', '1442321931567394820', 'Not a Node.js developer? No problem.                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 The latest @Acurast examples show how the new Cargo runtime lets you bring your own language and tooling to decentralized hardware.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Run Python scripts, native Rust binaries, Go programs, Zig builds, custom CLIs, and more.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Try it out here:                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
 https://github.com/Acurast/acurast-example-apps/tree/main/apps', '2069088482618712082', NULL, NULL, '2069372603408826424', 3, 0, 55, 0, 0, '2026-06-23 10:50:50+00', '2026-06-24 03:05:26.524207+00', '2026-06-24 03:05:26.524207+00', NULL, NULL, NULL, NULL, NULL);
 INSERT INTO mindshare.mindshare_post_test (post_id, project_keyword, user_x_id, full_text, retweeted_post_id, replied_post_id, quoted_post_id, root_post_id, view_count, reply_count, retweet_count, quote_count, favorite_count, post_created_at, created_at, updated_at, sentiment_score, sentiment_label, entities, content_score, latest_reply_at) VALUES ('2067754229297787262', 'Acurast', '1442321931567394820', 'In our recent CoinMarketCap Space, Alessandro got the question he''s heard since day one: building a compute network out of smartphones sounded strange to a lot of people at first.                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Here''s the case that changes minds: your phone is already a reliable, always-on computer. Think about how long your alarm clock phone goes without a restart. Weeks. Months.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Acurast never runs in the background, so you choose when to dedicate a device. Overnight while it charges, or full-time with a spare. Either way, it just keeps going.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 See the clip from the Space below.', '2067645881201963453', NULL, NULL, '2067754229297787262', 0, 0, 40, 0, 0, '2026-06-18 23:39:59+00', '2026-06-19 03:05:09.502469+00', '2026-06-19 03:05:09.502469+00', NULL, NULL, NULL, NULL, NULL);
 INSERT INTO mindshare.mindshare_post_test (post_id, project_keyword, user_x_id, full_text, retweeted_post_id, replied_post_id, quoted_post_id, root_post_id, view_count, reply_count, retweet_count, quote_count, favorite_count, post_created_at, created_at, updated_at, sentiment_score, sentiment_label, entities, content_score, latest_reply_at) VALUES ('2067400708471861448', 'Acurast', '1442321931567394820', 'Want to join Acurast as a provider?                                                                                                                                                                                                                                                                                                                                                            +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 There are two ways to start and get rewarded:                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Core: dedicated device, always-on, maximum rewards, and full staking participation option. Built for serious providers focused on long-term yield and network contribution.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Lite: app-based, flexible, get rewarded whenever you keep the app open. Perfect for getting started without commitment.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Either path strengthens the decentralized network. Either path gets you ACU tokens.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Want to do more? With The Cloud Rebellion you can participate in our community platform, complete tasks and receive MIST points in return.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Get started here:                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 https://acurast.com/providers/?utm_source=x&utm_medium=social&utm_campaign=onboarding&utm_content=appstore', '2067276130210492464', NULL, NULL, '2067400708471861448', 0, 0, 36, 0, 0, '2026-06-18 00:15:14+00', '2026-06-18 03:04:36.981697+00', '2026-06-18 03:04:36.981697+00', NULL, NULL, NULL, NULL, NULL);
 INSERT INTO mindshare.mindshare_post_test (post_id, project_keyword, user_x_id, full_text, retweeted_post_id, replied_post_id, quoted_post_id, root_post_id, view_count, reply_count, retweet_count, quote_count, favorite_count, post_created_at, created_at, updated_at, sentiment_score, sentiment_label, entities, content_score, latest_reply_at) VALUES ('2065485119394316548', 'Acurast', '1442321931567394820', 'Builder Spotlight: a private LLM running on a single phone, reachable as a standard OpenAI endpoint by @nodeghostai 🔥                                                                                                                                                                                                                                                                          +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 No hosted API, no rented cloud GPU. The model runs on one attested Acurast processor. The Acurast tunnel makes that locally-bound model reachable at a public HTTPS URL, and NodeGhost serves it as a drop-in OpenAI-compatible endpoint through Bring Your Own Model.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 It''s an ordinary OpenAI call. The machine answering it is a phone.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 One quantized Qwen2.5-3B model, one tunnel, one registration step. Deployable on Canary today, and honest about what a 3B model does on a mobile CPU.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Full breakdown:                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 https://acurast.com/blog/builder-spotlight/?utm_source=x&utm_medium=social&utm_campaign=developer&utm_content=acurast-builder-spotlight-tunnel-nodeghost', '2065479340465246720', NULL, NULL, '2065485119394316548', 0, 0, 43, 0, 0, '2026-06-12 17:23:21+00', '2026-06-13 03:04:21.954757+00', '2026-06-13 03:04:21.954757+00', NULL, NULL, NULL, NULL, NULL);
