 INSERT INTO mindshare.mindshare_post_test (post_id, project_keyword, user_x_id, full_text, retweeted_post_id, replied_post_id, quoted_post_id, root_post_id, view_count, reply_count, retweet_count, quote_count, favorite_count, post_created_at, created_at, updated_at, sentiment_score, sentiment_label, entities, content_score, latest_reply_at) VALUES ('2062054546092757200', 'Acurast', '1206994083438321666', 'The next guest should be a team actively building the infrastructure that enables autonomous agents to operate, transact, and scale in the real world. As agents move beyond screens and into the Machine Economy, topics like decentralized compute, identity, payments, data ownership, and machine-to-machine coordination become increasingly important.                                   +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 After insightful discussions with @Acurast and @FolksFinance, it would be fascinating to hear from builders working on AI agents, DePIN, autonomous finance, or on-chain reputation systems. Understanding how these pieces connect will help paint a clearer picture of the future where machines don''t just assist humans they actively participate in the economy.                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 The Machine Economy is no longer a distant concept; it''s being built today. 🚀                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 @konnex_world can make it possible !', '2062041928774861185', NULL, NULL, '2062054546092757200', 0, 0, 5, 0, 0, '2026-06-03 06:11:29+00', '2026-06-04 03:21:32.87397+00', '2026-06-04 03:21:32.87397+00', NULL, NULL, NULL, NULL, NULL);
