 INSERT INTO mindshare.mindshare_post_test (post_id, project_keyword, user_x_id, full_text, retweeted_post_id, replied_post_id, quoted_post_id, root_post_id, view_count, reply_count, retweet_count, quote_count, favorite_count, post_created_at, created_at, updated_at, sentiment_score, sentiment_label, entities, content_score, latest_reply_at) VALUES ('2047172551395418375', 'Acurast', '1442321931567394820', 'Our community doesn''t just hold, they build, post, complete quests, and show up.                                                                                                                                                                                                                                                                                                              +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 The Cloud Rebellion is where that energy gets rewarded.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Participate in quests, grow the network, harvest your MIST points.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Two new quests just dropped, jump in.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 https://hub.acurast.com/rebellion/dashboard?utm_source=x&utm_medium=social&utm_campaign=announcement&utm_content=hub https://pbs.twimg.com/media/HGhXol9WAAACL9m.jpg', '2046982390795342062', NULL, NULL, '2047172551395418375', 0, 0, 74, 0, 0, '2026-04-23 04:35:45+00', '2026-05-12 13:21:10.983069+00', '2026-05-12 13:21:10.983069+00', NULL, NULL, NULL, NULL, NULL);
 INSERT INTO mindshare.mindshare_post_test (post_id, project_keyword, user_x_id, full_text, retweeted_post_id, replied_post_id, quoted_post_id, root_post_id, view_count, reply_count, retweet_count, quote_count, favorite_count, post_created_at, created_at, updated_at, sentiment_score, sentiment_label, entities, content_score, latest_reply_at) VALUES ('2045548177206681933', 'Acurast', '1442321931567394820', 'Your AI agent can now pay for its own compute. Works with Claude, Coinbase Agentic Wallet, and more.                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Until now, every agent had a leash. It could reason, plan and execute, but the moment it needed to pay for something, it had to stop and ask.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 As a user, you had to approve and a wallet had to be set up. The machine waited on the person.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 That gap is what''s held the whole industry back, and x402 closes it.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Acurast now supports x402 on Base.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 x402 is the payment standard built natively into agentic wallets, meaning agents can request, pay for, and deploy jobs on their own, no human in the loop.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Here''s how it works:                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 1. Agent requests a job deployment                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
 2. Deploy Agent requests payment via x402                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
 3. Payment confirmed. Job deployed. Agent keeps moving.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 No wallet setup, no token bridging and no manual approvals.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Just agents doing what they were built to do.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 x402 handles the payments.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 Acurast handles the compute. 🤝                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 Try it now:                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
 https://docs.acurast.com/developers/deploy-agent/?utm_source=x&utm_medium=social&utm_campaign=product_update', '2045532837072228359', NULL, NULL, '2045548177206681933', 0, 0, 87, 0, 0, '2026-04-18 17:01:04+00', '2026-05-12 13:21:10.983069+00', '2026-05-12 13:21:10.983069+00', NULL, NULL, NULL, NULL, NULL);
